using System.ComponentModel;
using System.Drawing.Design;
using System.Windows.Forms;
using System.Windows.Forms.Design;

public class MyControl : UserControl
{
    private readonly StatusStrip _statusStrip;

    public MyControl()
    {
        _statusStrip = new StatusStrip();
        // .NET 9 breaking change: StatusStrip no longer defaults to System rendering.
        // Explicitly set RenderMode to preserve .NET 8 visual behavior.
        _statusStrip.RenderMode = ToolStripRenderMode.System;
        Controls.Add(_statusStrip);
    }

    [Editor(typeof(MyControlEditor), typeof(UITypeEditor))]
    public string DisplayName { get; set; } = string.Empty;

    public int MaxItems { get; set; }
}

public class MyControlEditor : UITypeEditor
{
    public override UITypeEditorEditStyle GetEditStyle(ITypeDescriptorContext? context)
        => UITypeEditorEditStyle.DropDown;

    public override object? EditValue(
        ITypeDescriptorContext? context,
        IServiceProvider? provider,
        object? value)
    {
        if (provider?.GetService(typeof(IWindowsFormsEditorService))
            is not IWindowsFormsEditorService editorService)
            return value;

        var control = new TextBox { Text = value as string ?? string.Empty };

        // .NET 9 breaking change: DropDownControl(null) now throws ArgumentNullException.
        // Always guard against null before calling.
        if (control is not null)
        {
            editorService.DropDownControl(control);
        }

        return control?.Text ?? value;
    }
}

