using System.Net.Http;
using System.Runtime.InteropServices;
using System.Windows.Forms;

partial class ImageLoader
{
    // .NET 9: Use LibraryImport instead of DllImport for better perf and AOT support.
    [LibraryImport("gdi32.dll", SetLastError = true)]
    [return: MarshalAs(UnmanagedType.Bool)]
    private static partial bool DeleteObject(IntPtr hObject);

    void LoadImage(PictureBox pictureBox, string url)
    {
        // .NET 9 breaking change: PictureBox.Load uses HttpClient internally,
        // so failures throw HttpRequestException instead of WebException.
        try { pictureBox.Load(url); }
        catch (HttpRequestException ex) { Console.WriteLine("Failed: " + ex.Message); }
    }
}

